<?php
namespace App\Http\Resources; use Illuminate\Http\Request; use Illuminate\Http\Resources\Json\JsonResource;
class GameResource extends JsonResource { public function toArray(Request $request): array { $hands=\Illuminate\Support\Facades\DB::table('game_cards')->join('cards','cards.id','=','game_cards.card_id')->where('game_cards.game_id',$this->id)->whereNotNull('game_cards.user_id')->get(['game_cards.user_id','cards.id','cards.title','cards.subtitle','cards.score','cards.image','cards.deck'])->map(function($card){$card->score=(float)$card->score;return $card;})->groupBy('user_id'); return ['id'=>$this->id,'code'=>$this->code,'owner_id'=>$this->owner_id,'started'=>$this->started,'current_player_id'=>$this->current_player_id,'turn_owner_id'=>$this->turn_owner_id,'awaiting_finish'=>$this->awaiting_finish,'is_steal_turn'=>$this->is_steal_turn,'ingame_polling_interval_ms'=>config('game.ingame_polling_interval_ms'),'current_card'=>new CardResource($this->whenLoaded('currentCard')),'members'=>UserResource::collection($this->whenLoaded('members')),'hands'=>$hands,'moves'=>MoveResource::collection($this->whenLoaded('moves')),'created_at'=>$this->created_at]; } }
